import{_ as t,o,c as a,a0 as s}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"Feature Recommendations","description":"","frontmatter":{},"headers":[],"relativePath":"feature-recommendations.md","filePath":"feature-recommendations.md","lastUpdated":1784483059000}'),r={name:"feature-recommendations.md"};function n(i,e,d,c,l,p){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="feature-recommendations" tabindex="-1">Feature Recommendations <a class="header-anchor" href="#feature-recommendations" aria-label="Permalink to &quot;Feature Recommendations&quot;">​</a></h1><p>Status: <strong>all 13 items implemented</strong> (see the per-item status notes below; #11 is implemented as guidance-only, per its own proposal&#39;s lower-effort path — see its note). This document extends the SDS&#39;s own &quot;Future Roadmap&quot; (Phases 9–12: Playwright E2E, Accessibility Automation, Visual Regression Testing, Nuxt/SSR/Theme Management) with concrete recommendations identified by reviewing the current <code>v1.0.0</code> implementation against real usage patterns. Each item lists the gap it addresses, a sketch of the API, and a rough effort/impact call so they can be triaged into a sprint.</p><p>Organized <strong>Now / Next / Later</strong>, the same shorthand used in the SDS for early-stage planning — not a committed schedule.</p><hr><h2 id="now-high-value-low-to-medium-effort" tabindex="-1">Now (high value, low-to-medium effort) <a class="header-anchor" href="#now-high-value-low-to-medium-effort" aria-label="Permalink to &quot;Now (high value, low-to-medium effort)&quot;">​</a></h2><h3 id="_1-distinguish-external-asset-load-failures-from-document-access-failures-—-✅-implemented" tabindex="-1">1. Distinguish external asset load failures from document-access failures — ✅ Implemented <a class="header-anchor" href="#_1-distinguish-external-asset-load-failures-from-document-access-failures-—-✅-implemented" aria-label="Permalink to &quot;1. Distinguish external asset load failures from document-access failures — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> <code>injectCssUrlIntoDocument</code>/<code>injectJsUrlIntoDocument</code> create the <code>&lt;link&gt;</code>/ <code>&lt;script&gt;</code> element and resolve successfully the moment the element is <em>inserted</em> — a 404 or network failure on the URL itself never surfaces. Today, a broken <code>cssUrls</code>/ <code>jsUrls</code> entry fails silently from the host application&#39;s point of view.</p><p><strong>Proposal:</strong> Attach <code>load</code>/<code>error</code> listeners to the created element and resolve/reject the injection result asynchronously (or emit a new <code>asset-error</code> event distinct from the existing synchronous <code>error</code>). This changes <code>IframeInjectionResult</code> to optionally carry a <code>status: &#39;pending&#39; | &#39;loaded&#39; | &#39;failed&#39;</code> that updates in place.</p><p><strong>Effort:</strong> S · <strong>Impact:</strong> High (silent failures are the #1 support-ticket generator for asset-injection libraries).</p><p><strong>Status:</strong> <code>IframeInjectionResult</code> now carries <code>status: &#39;pending&#39; | &#39;loaded&#39; | &#39;failed&#39;</code>, updated in place as the underlying element&#39;s native <code>load</code>/<code>error</code> fires. The component emits a new <code>assetError</code> event, distinct from the synchronous <code>error</code> event. See <a href="/api/parameters#iframeinjectionresult">Parameters → <code>IframeInjectionResult</code></a> and <code>tests/iframe-injection.spec.ts</code>&#39;s &quot;asset load status tracking&quot; suite.</p><hr><h3 id="_2-allow-referrerpolicy-loading-and-allowfullscreen-passthrough-props-—-✅-implemented" tabindex="-1">2. <code>allow</code>, <code>referrerpolicy</code>, <code>loading</code>, and <code>allowfullscreen</code> passthrough props — ✅ Implemented <a class="header-anchor" href="#_2-allow-referrerpolicy-loading-and-allowfullscreen-passthrough-props-—-✅-implemented" aria-label="Permalink to &quot;2. `allow`, `referrerpolicy`, `loading`, and `allowfullscreen` passthrough props — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> The component only exposes <code>sandbox</code> and <code>title</code> from the native iframe attribute surface. Common enterprise needs — <code>allow=&quot;clipboard-write&quot;</code> for copy-to-clipboard previews, <code>referrerpolicy=&quot;no-referrer&quot;</code> for privacy-sensitive embeds, <code>loading=&quot;lazy&quot;</code> for below-the-fold previews — currently require the consumer to fork the component or reach past it with a ref.</p><p><strong>Proposal:</strong> Add <code>allow?: string</code>, <code>referrerPolicy?: ReferrerPolicy</code>, <code>loading?: &#39;eager&#39; | &#39;lazy&#39;</code>, <code>allowFullscreen?: boolean</code> props, bound straight through to the underlying <code>&lt;iframe&gt;</code>.</p><p><strong>Effort:</strong> XS · <strong>Impact:</strong> Medium-High (frequently requested, trivial to implement).</p><p><strong>Status:</strong> All four props added exactly as proposed, bound straight through to the iframe. See <a href="/api/parameters#appearance-props">Parameters → Appearance props</a>.</p><hr><h3 id="_3-loading-error-slots-—-✅-implemented" tabindex="-1">3. Loading / error slots — ✅ Implemented <a class="header-anchor" href="#_3-loading-error-slots-—-✅-implemented" aria-label="Permalink to &quot;3. Loading / error slots — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> There is no visual feedback between mount and the first <code>load</code> event, and no built-in way to show a fallback UI when <code>error</code> fires. Every consumer re-implements the same &quot;spinner over the iframe&quot; pattern.</p><p><strong>Proposal:</strong> Named slots — <code>#loading</code> (shown until first <code>load</code>) and <code>#error</code> (shown when the most recent action produced an <code>IframeError</code>), with the error made available as slot props (<code>#error=&quot;{ error }&quot;</code>).</p><p><strong>Effort:</strong> S · <strong>Impact:</strong> Medium-High (removes boilerplate from nearly every real consumer).</p><p><strong>Status:</strong> Implemented as proposed — <code>#loading</code> and <code>#error=&quot;{ error }&quot;</code> slots. This required promoting the component&#39;s root from the bare <code>&lt;iframe&gt;</code> to a wrapper <code>&lt;div&gt;</code> (to host the slots as absolutely-positioned overlays alongside the iframe, which must stay mounted to keep firing <code>load</code> events); <code>inheritAttrs: false</code> plus an explicit <code>v-bind=&quot;$attrs&quot;</code> on the iframe preserves the previous passthrough-attribute behavior (verified directly — see <code>tests/IframeWrapper.spec.ts</code>&#39;s data-testid passthrough test).</p><hr><h3 id="_4-auto-height-via-resizeobserver-—-✅-implemented" tabindex="-1">4. Auto-height via <code>ResizeObserver</code> — ✅ Implemented <a class="header-anchor" href="#_4-auto-height-via-resizeobserver-—-✅-implemented" aria-label="Permalink to &quot;4. Auto-height via `ResizeObserver` — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> <code>iframeStyle</code>/<code>iframeClass</code> require the host to know the content&#39;s height up front. For <code>srcdoc</code> previews of variable-height content (reports, emails, CMS blocks), consumers currently poll <code>getDocument()?.body.scrollHeight</code> themselves.</p><p><strong>Proposal:</strong> An opt-in <code>autoHeight?: boolean</code> prop that attaches a <code>ResizeObserver</code> to the injected document&#39;s <code>&lt;body&gt;</code> (same-origin only, naturally) and updates the iframe&#39;s height to match, emitting a new <code>resize</code> event with the measured height for consumers who want to react to it themselves instead.</p><p><strong>Effort:</strong> M · <strong>Impact:</strong> High for the &quot;report/CMS preview&quot; use case called out explicitly in the SDS&#39;s business objectives.</p><p><strong>Status:</strong> Implemented as proposed — <code>autoHeight</code> prop, <code>resize</code> event. jsdom has no real <code>ResizeObserver</code> implementation or layout engine, so <code>tests/mocks/resize-observer.ts</code> provides a manually-triggerable mock for deterministic tests rather than relying on real (always-zero, in jsdom) geometry.</p><hr><h3 id="_5-deduplicate-repeated-jsurls-cssurls-injections-across-remounts-—-✅-implemented" tabindex="-1">5. Deduplicate repeated <code>jsUrls</code>/<code>cssUrls</code> injections across remounts — ✅ Implemented <a class="header-anchor" href="#_5-deduplicate-repeated-jsurls-cssurls-injections-across-remounts-—-✅-implemented" aria-label="Permalink to &quot;5. Deduplicate repeated `jsUrls`/`cssUrls` injections across remounts — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> <code>replaceExisting</code> (default <code>true</code>) only deduplicates within a single injection <code>id</code>. Two different <code>IframeWrapper</code> instances (or the same one across a fast reload-heavy flow) injecting the same external script URL will each create their own <code>&lt;script&gt;</code> tag with a different auto-generated id, potentially re-executing scripts with global side effects more than intended.</p><p><strong>Proposal:</strong> Default <code>id</code> generation for <code>*Url</code> variants to a hash of the URL itself (rather than a counter), so the same URL naturally collides into one element regardless of call site — opt out via an explicit <code>id</code> when duplication is actually wanted.</p><p><strong>Effort:</strong> XS · <strong>Impact:</strong> Medium (correctness fix more than a new feature).</p><p><strong>Status:</strong> <code>createUrlInjectionId</code> now hashes the URL (a small FNV-1a-like mix, not cryptographic — collision-resistance for this purpose only) instead of using a counter. Same URL, no explicit id, from any call site → same generated id → natural dedup via the existing <code>replaceExisting: true</code> default.</p><hr><h2 id="next-medium-to-high-value-medium-effort" tabindex="-1">Next (medium-to-high value, medium effort) <a class="header-anchor" href="#next-medium-to-high-value-medium-effort" aria-label="Permalink to &quot;Next (medium-to-high value, medium effort)&quot;">​</a></h2><h3 id="_6-useiframemessage-composable-typed-postmessage-bridge-—-✅-implemented" tabindex="-1">6. <code>useIframeMessage</code> composable (typed <code>postMessage</code> bridge) — ✅ Implemented <a class="header-anchor" href="#_6-useiframemessage-composable-typed-postmessage-bridge-—-✅-implemented" aria-label="Permalink to &quot;6. `useIframeMessage` composable (typed `postMessage` bridge) — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> The library deliberately stays out of cross-document messaging, but almost every real integration needs <em>some</em> host↔iframe communication (e.g. &quot;tell the host the form inside was submitted&quot;). Consumers currently hand-roll <code>window.addEventListener(&#39;message&#39;, ...)</code> with no origin-checking guidance.</p><p><strong>Proposal:</strong> A <code>useIframeMessage&lt;TIn, TOut&gt;(iframeRef, options)</code> composable providing <code>send(message: TOut)</code> and an <code>onMessage(handler: (message: TIn) =&gt; void)</code> subscription, with mandatory <code>targetOrigin</code> (defaulting to same-origin, matching the library&#39;s existing security posture) and a documented pattern for the two-way handshake.</p><p><strong>Effort:</strong> M · <strong>Impact:</strong> High — this is the most-requested &quot;escape hatch&quot; for libraries in this space, and doing it inside the library means the security guidance (origin checks) is enforced rather than merely documented.</p><p><strong>Status:</strong> Implemented with <code>targetOrigin</code> optional (defaulting to same-origin) rather than mandatory as originally sketched — a sensible default matching the library&#39;s existing posture was more ergonomic than forcing every call site to state it. An SSR audit (see <a href="/guide/ssr">SSR / Nuxt Guidance</a>) found this composable&#39;s first draft would have thrown on the server (<code>window.location.origin</code> accessed unconditionally); fixed and verified with a test running in a genuine Node environment with no <code>window</code> global (<code>tests/useIframeMessage.ssr.spec.ts</code>).</p><hr><h3 id="_7-accessibility-automation-sds-phase-10-made-concrete-—-✅-implemented" tabindex="-1">7. Accessibility automation (SDS Phase 10, made concrete) — ✅ Implemented <a class="header-anchor" href="#_7-accessibility-automation-sds-phase-10-made-concrete-—-✅-implemented" aria-label="Permalink to &quot;7. Accessibility automation (SDS Phase 10, made concrete) — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> The SDS lists &quot;Accessibility Automation&quot; as planned but unscoped. The demo app and component currently rely on the consumer supplying <code>title</code>; there&#39;s no automated check that catches a regression (e.g. someone removing the <code>title</code> binding).</p><p><strong>Proposal:</strong> <code>axe-core</code> + <code>@axe-core/playwright</code> integrated into a new <code>a11y</code> test project, asserting: iframe always has an accessible name, focus is not trapped unexpectedly, and the demo app&#39;s controls are keyboard-operable end to end.</p><p><strong>Effort:</strong> M · <strong>Impact:</strong> Medium-High, and derisks enterprise procurement reviews that specifically ask for accessibility test evidence (common in the public-sector / enterprise procurement space this library targets).</p><p><strong>Status:</strong> Implemented in two layers. First, <code>jest-axe</code>&#39;s <code>axe()</code> runner in the jsdom unit suite (lower effort, covers &quot;iframe always has an accessible name&quot; for both the library and demo app — <code>tests/IframeWrapper.a11y.spec.ts</code> and <code>demo/tests/App.a11y.spec.ts</code>, the latter catching two real, since-fixed issues: unlabeled textareas, a live log with no <code>aria-live</code>). Later, the originally-sketched <code>@axe-core/playwright</code> was added too — <code>tests-e2e/accessibility.spec.ts</code> and <code>demo-accessibility.spec.ts</code> — covering exactly the two things jsdom cannot: real color-contrast calculation and genuine keyboard Tab-order/focus behavior, closing this item&#39;s &quot;focus is not trapped&quot; and &quot;keyboard-operable end to end&quot; clauses that the jsdom-only pass couldn&#39;t fully address. See <a href="/enterprise-readiness">Enterprise Readiness</a> Phase 3 (jsdom layer) and Phase 4 (real-browser layer), and <a href="/accessibility">Accessibility</a>.</p><hr><h3 id="_8-playwright-e2e-suite-sds-phase-9-made-concrete-—-✅-implemented" tabindex="-1">8. Playwright E2E suite (SDS Phase 9, made concrete) — ✅ Implemented <a class="header-anchor" href="#_8-playwright-e2e-suite-sds-phase-9-made-concrete-—-✅-implemented" aria-label="Permalink to &quot;8. Playwright E2E suite (SDS Phase 9, made concrete) — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> Current tests are unit/component-level with jsdom, which cannot fully verify real cross-origin behavior, actual <code>sandbox</code> enforcement, or genuine <code>ResizeObserver</code> timing (relevant once #4 lands).</p><p><strong>Proposal:</strong> A <code>tests-e2e/</code> Playwright suite covering: same-origin injection against a real browser engine, sandbox attribute enforcement (attempting a disallowed action and asserting it&#39;s blocked), and the reload/<code>reloadKey</code> flow against real navigation timing.</p><p><strong>Effort:</strong> M · <strong>Impact:</strong> Medium-High — closes the largest gap between &quot;tests pass&quot; and &quot;works in production browsers.&quot;</p><p><strong>Status:</strong> Implemented exactly as scoped, plus a genuine cross-origin scenario (a second server on a different port) that wasn&#39;t explicitly named here. See <a href="/guide/testing">Testing → End-to-end tests</a> — including the disclosed limitation that this sandboxed environment couldn&#39;t download Playwright browser binaries to actually execute the suite, only write and statically validate it.</p><hr><h3 id="_9-declarative-per-asset-placement-and-id-—-✅-implemented" tabindex="-1">9. Declarative per-asset <code>placement</code> and <code>id</code> — ✅ Implemented <a class="header-anchor" href="#_9-declarative-per-asset-placement-and-id-—-✅-implemented" aria-label="Permalink to &quot;9. Declarative per-asset `placement` and `id` — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> <code>placement</code> and <code>id</code> are only configurable through the imperative <code>InjectionOptions</code> API (see <a href="/api/parameters#prop-interactions--precedence-rules">Parameters → Prop interactions</a>). Declarative consumers who need, say, one CSS block in <code>&lt;body&gt;</code> for a scoped style tag currently must drop into manual mode entirely just for that one asset.</p><p><strong>Proposal:</strong> Allow <code>css</code>/<code>js</code> (and their <code>*Urls</code> siblings) to optionally accept an array of <code>{ value: string; id?: string; placement?: IframeAssetPlacement }</code> objects alongside the existing plain-string shorthand, resolved through the same <code>injectConfiguredAssets</code> path.</p><p><strong>Effort:</strong> M · <strong>Impact:</strong> Medium (a real but relatively narrow gap).</p><p><strong>Status:</strong> Implemented as <code>IframeAssetInput</code> (string | string[] | <code>IframeAssetDescriptor[]</code>), with descriptor objects also carrying <code>replaceExisting</code> and <code>nonce</code> (not just <code>id</code>/<code>placement</code> as originally sketched — barely more code for meaningfully more flexibility). See <a href="/api/parameters#asset-props">Parameters → Asset props</a>.</p><hr><h3 id="_10-vue-devtools-custom-inspector-—-✅-implemented" tabindex="-1">10. Vue Devtools custom inspector — ✅ Implemented <a class="header-anchor" href="#_10-vue-devtools-custom-inspector-—-✅-implemented" aria-label="Permalink to &quot;10. Vue Devtools custom inspector — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> Debugging <em>what</em> was injected and <em>when</em> currently means reading console logs from the <code>injected</code>/<code>error</code> events by hand.</p><p><strong>Proposal:</strong> A Devtools plugin panel listing, per <code>IframeWrapper</code> instance, the current injected assets (id/type/placement), a timeline of <code>load</code>/<code>injected</code>/<code>error</code> events, and a button to re-run <code>injectConfiguredAssets</code> for quick iteration during development.</p><p><strong>Effort:</strong> M · <strong>Impact:</strong> Medium (developer-experience multiplier, not user-facing).</p><p><strong>Status:</strong> Implemented — a registry of mounted instances (<code>src/devtools/registry.ts</code>) feeding a custom inspector panel (<code>src/devtools/plugin.ts</code>). Two real problems surfaced and fixed during implementation: (1) <code>@vue/devtools-api@8.x</code> bundled ~27 KB gzipped via <code>@vue/devtools-kit</code>, blowing the size budget 4-5x — swapped to the lightweight legacy <code>6.x</code> line, the same one Pinia/Vue Router use; (2) <code>6.x</code>&#39;s own shipped types are incompatible with newer Vue versions (<code>vue-tsc</code> circular-reference errors) — worked around with a small local type shim rather than suppressing the checker. See <a href="/guide/devtools">Vue Devtools Integration</a> for the full account, including the disclosed limitation that no real Devtools browser session was available to visually confirm the panel end-to-end.</p><hr><h2 id="later-strategic-higher-effort" tabindex="-1">Later (strategic, higher effort) <a class="header-anchor" href="#later-strategic-higher-effort" aria-label="Permalink to &quot;Later (strategic, higher effort)&quot;">​</a></h2><h3 id="_11-nuxt-module-ssr-guidance-sds-phase-12-—-✅-implemented-guidance-only" tabindex="-1">11. Nuxt module + SSR guidance (SDS Phase 12) — ✅ Implemented (guidance-only) <a class="header-anchor" href="#_11-nuxt-module-ssr-guidance-sds-phase-12-—-✅-implemented-guidance-only" aria-label="Permalink to &quot;11. Nuxt module + SSR guidance (SDS Phase 12) — ✅ Implemented (guidance-only)&quot;">​</a></h3><p><strong>Gap:</strong> The library is Vite/Vue-only today; nothing has been verified under Nuxt&#39;s SSR/hydration lifecycle, where <code>IframeWrapper</code> would need to render a placeholder server-side and hydrate into the real iframe client-side only.</p><p><strong>Proposal:</strong> A thin <code>@enterprise/nuxt-iframe-wrapper</code> module registering the component globally, with explicit <code>&lt;ClientOnly&gt;</code>-equivalent handling built in, plus documented guidance for SSR frameworks generally (Nuxt, Vite SSR, Quasar) even for consumers not using the dedicated module.</p><p><strong>Effort:</strong> L · <strong>Impact:</strong> Medium — expands addressable audience but is a genuinely separate integration surface to maintain long-term.</p><p><strong>Status:</strong> The dedicated <code>@enterprise/nuxt-iframe-wrapper</code> module is <strong>not</strong> built — per <a href="/enterprise-readiness">Enterprise Readiness → Phase 6</a>, that&#39;s deliberately deferred until there&#39;s validated demand, since it&#39;s the one item that opens a new long-term maintenance surface rather than hardening the existing library. What <em>is</em> done: an actual SSR-safety audit (not just an assumption) of every composable, which found and fixed a real bug in <code>useIframeMessage</code> (see #6&#39;s status above), plus documented <code>&lt;ClientOnly&gt;</code>/manual-hydration guidance. See <a href="/guide/ssr">SSR / Nuxt Guidance</a>.</p><hr><h3 id="_12-visual-regression-testing-sds-phase-11-made-concrete-—-✅-implemented" tabindex="-1">12. Visual regression testing (SDS Phase 11, made concrete) — ✅ Implemented <a class="header-anchor" href="#_12-visual-regression-testing-sds-phase-11-made-concrete-—-✅-implemented" aria-label="Permalink to &quot;12. Visual regression testing (SDS Phase 11, made concrete) — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> No automated protection today against a CSS or layout regression in the demo app or the component&#39;s own minimal default styles.</p><p><strong>Proposal:</strong> Playwright&#39;s built-in screenshot comparison (reusing the E2E suite from #8) against the demo app&#39;s key states: initial load, post-CSS-injection, error state (once #3 lands), and the auto-height case (once #4 lands).</p><p><strong>Effort:</strong> M-L (mostly maintenance cost over time from baseline churn) · <strong>Impact:</strong> Medium.</p><p><strong>Status:</strong> Implemented against the E2E harness (not the demo app as sketched — a purpose-built harness proved lower-effort) with four scenarios covering states the library actually has today; the error-state and auto-height scenarios mentioned in the original proposal are intentionally deferred to whenever a consumer of this list actually needs them, now that both features exist. Includes the baseline-review process this phase&#39;s own effort estimate flagged as the real cost — see <a href="/guide/visual-regression">Visual Regression</a>.</p><hr><h3 id="_13-theme-management-helpers-—-✅-implemented" tabindex="-1">13. Theme management helpers — ✅ Implemented <a class="header-anchor" href="#_13-theme-management-helpers-—-✅-implemented" aria-label="Permalink to &quot;13. Theme management helpers — ✅ Implemented&quot;">​</a></h3><p><strong>Gap:</strong> &quot;Theme Management&quot; is named in the SDS roadmap without detail. The closest existing primitive is calling <code>injectCss</code> with a stable <code>id</code> (see <a href="/guide/examples#manual-api">Examples → Manual API</a>), which works but requires each consumer to invent their own theme-object-to-CSS-string conversion.</p><p><strong>Proposal:</strong> An optional <code>useIframeTheme(frame, themeTokens)</code> composable that accepts a plain design-token object (colors, spacing, fonts) and generates/updates a single <code>:root { --token: value; }</code> custom-properties block inside the iframe via <code>injectCss</code>, so host and iframe can share a design-token source of truth without the consumer hand-writing CSS strings.</p><p><strong>Effort:</strong> L · <strong>Impact:</strong> Medium — valuable for the &quot;theme previews&quot; use case named explicitly in the SDS, but speculative until a concrete consumer requests it.</p><p><strong>Status:</strong> Implemented as <code>useIframeTheme(frame, options)</code> plus the lower-level <code>injectThemeTokens(doc, tokens, options)</code> and standalone <code>themeTokensToCss(tokens)</code> helpers, converting <code>camelCase</code>/<code>PascalCase</code> token keys to <code>--kebab-case</code> custom properties automatically. Built directly on <code>injectCss</code> with a stable default id, so repeated calls replace the previous theme block in place — the basis for a live theme switcher.</p><hr><h2 id="explicitly-out-of-scope" tabindex="-1">Explicitly out of scope <a class="header-anchor" href="#explicitly-out-of-scope" aria-label="Permalink to &quot;Explicitly out of scope&quot;">​</a></h2><p>Carried over from the SDS&#39;s own security design, and worth restating so future feature requests against these are triaged as &quot;won&#39;t do&quot; rather than re-litigated:</p><ul><li>Cross-origin iframe injection or any same-origin-policy bypass.</li><li>A sandboxed execution environment for genuinely untrusted third-party HTML (this library previews content <em>you</em> control — see <a href="/security">Security</a>).</li><li>Server-side rendering/execution of injected JavaScript (injection is a DOM operation, not a script-evaluation sandbox).</li></ul><h2 id="suggested-next-step" tabindex="-1">Suggested next step <a class="header-anchor" href="#suggested-next-step" aria-label="Permalink to &quot;Suggested next step&quot;">​</a></h2><p>All 13 items above are now implemented (see each item&#39;s <strong>Status</strong> note for exactly what shipped and what changed from the original sketch). The one item genuinely left open by design is the dedicated <code>@enterprise/nuxt-iframe-wrapper</code> package described under #11 — that&#39;s a decision to make when real Nuxt usage demand shows up, not a task to pick up next. Beyond that, see <a href="/enterprise-readiness">Enterprise Readiness</a> for what&#39;s left on the broader readiness checklist (an SBOM, dedicated Playwright-side accessibility assertions, and a couple of manual one-time repo-settings actions).</p>',90)])])}const u=t(r,[["render",n]]);export{h as __pageData,u as default};
